        self.word_counts = self.count_words()

    def count_words(self):
        # Split text into words and count occurrences
        words = word_tokenize(self.train_text)
        return Counter(words)

    def calculate_probability(self, word):
        # Calculate the probability of a word given the language model
        return self.word_counts[word] / len(self.word_counts)

    def perplexity(self, test_text):
        # Calculate the perplexity of a test set
        test_words = word_tokenize(test_text)
        total_words = len(test_words)
        perplexity = 1
        for word in test_words:
            probability = self.calculate_probability(word)
            perplexity *= (1 / probability)
        return math.exp(-total_words / perplexity)


